+        .and_then(sanitize_retry_after_seconds)
+        .or_else(|| {
+            serde_json::from_slice::<DiscordRateLimitBody>(body)
+                .ok()
+                .and_then(|body| body.retry_after)
+                .and_then(sanitize_retry_after_seconds)
+        })
+        .unwrap_or(DEFAULT_RETRY_AFTER_SECONDS)
+}

